#include <bits/stdc++.h>
using namespace std;
int n,m;
long long dp[11][1<<10][82];
int siz(int x){
    int sum=0;
    while(x)
        sum+=x&1,x>>=1;
    return sum;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=0;j<1<<n;j++){
        	if((j&(j<<1)) || (j&(j>>1)))
        		continue;
            int len=siz(j);
            if(len>m)
            	continue;
            if(i==1){
                dp[i][j][len]=1;
                continue;
            }
            for(int k=len;k<=m;k++)
                for(int l=0;l<1<<n;l++)
                	if((j&(l<<1))==0 && (j&(l>>1))==0 && (j&l)==0 && len+siz(l)<=k)
                    	dp[i][j][k]+=dp[i-1][l][k-len];
        }
    long long ans=0;
    for(int i=0;i<1<<n;i++)
        ans+=dp[n][i][m];
    printf("%lld",ans);
    return 0;
}
